1	export function nextGeneration(liveCells: [number, number][]): [number, number][] {
2	  const liveSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));
3	
4	  const candidates = new Map<string, number>();
5	  for (const [x, y] of liveCells) {
6	    for (let dx = -1; dx <= 1; dx++) {
7	      for (let dy = -1; dy <= 1; dy++) {
8	        if (dx === 0 && dy === 0) continue;
9	        const key = `${x + dx},${y + dy}`;
10	        candidates.set(key, (candidates.get(key) || 0) + 1);
11	      }
12	    }
13	  }
14	
15	  const result: [number, number][] = [];
16	  for (const [key, count] of candidates) {
17	    const isAlive = liveSet.has(key);
18	    if (count === 3 || (isAlive && count === 2)) {
19	      const [x, y] = key.split(",").map(Number);
20	      result.push([x, y]);
21	    }
22	  }
23	
24	  return result;
25	}
26

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent living cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should create a living cell from exactly 3 live neighbors (reproduction)", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
16	    const result = nextGeneration(input);
17	    const sorted = (cells: [number, number][]) =>
18	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
19	    expect(sorted(result)).toEqual(sorted([[0, 0], [1, 0], [0, 1], [1, 1]]));
20	  });
21	  it("should keep a cell alive with exactly 2 neighbors (survival)", () => {
22	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0]];
23	    const result = nextGeneration(input);
24	    expect(result).toContainEqual([1, 0]);
25	  });
26	  it("should keep a cell alive with exactly 3 neighbors (survival)", () => {
27	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 1]];
28	    const result = nextGeneration(input);
29	    expect(result).toContainEqual([1, 0]);
30	  });
31	  it("should kill a cell with more than 3 neighbors (overpopulation)", () => {
32	    // Plus/cross pattern: center (1,1) has 4 neighbors → dies
33	    const input: [number, number][] = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
34	    const result = nextGeneration(input);
35	    expect(result).not.toContainEqual([1, 1]);
36	  });
37	  it("should preserve a block still life across a generation", () => {
38	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
39	    const result = nextGeneration(block);
40	    const sorted = (cells: [number, number][]) =>
41	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
42	    expect(sorted(result)).toEqual(sorted([[0, 0], [1, 0], [0, 1], [1, 1]]));
43	  });
